import React from "react"
import Card from "./Card"
import contacts from "../Contacts"

function App () {
    return(
        <div>
            <Card
                name={contacts[0].contactName}
                tel={contacts[0].contactTel}
                email={contacts[0].contactEmail}
            />
            <Card
                name={contacts[1].contactName}
                tel={contacts[1].contactTel}
                email={contacts[1].contactEmail}
            />
        </div>
    )
}

export default App;
